import{_ as a,o as t,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Google & iOS 14 FAQ","description":"","frontmatter":{"title":"Google & iOS 14 FAQ","slug":"google-ios-14-faq"},"headers":[],"relativePath":"marketer-hub/google-ios-14-faq.md","filePath":"marketer-hub/google-ios-14-faq.md"}'),s={name:"marketer-hub/google-ios-14-faq.md"};function r(n,e,l,p,d,m){return t(),o("div",null,[...e[0]||(e[0]=[i('<details><summary>What happens when a user installs an app, sees the ATT prompt, then deletes the app and reinstalls. Will they see the ATT prompt again?</summary><p>For the latest on Google&#39;s iOS 14 plans, please see <a href="./google-ios14.html">this documentation page</a> and <a href="https://blog.branch.io/googles-ios-14-update-what-it-means-for-mobile-marketers/?_gl=1*1pb1ro3*_ga*MTE0MjE4NTYxLjE3NDIyOTA2MTE.*_ga_KSDD8Y11CT*MTc0MjI5MDYxMC4xLjEuMTc0MjMwMDg2MC42MC4wLjA." target="_blank" rel="noreferrer">this blog post</a>.</p></details><details><summary>What does Google’s iOS 14 stance mean for Branch advertisers?</summary><p>With Google both not asking for tracking consent and expanding their use of modeled conversions, Branch will essentially no longer be able to receive iOS attribution data from the Conversion API.</p><p>Google has indicated that they plan to begin sharing SKAdNetwork data with MMPs later in 2021, at which point we will be able to show this data along with your SKAdNetwork data from other ad networks.</p><p>If an advertiser is running a web campaign using a Branch tracking link, this should remain unaffected.</p></details><details><summary>Do apps have to use the Firebase SDK for Google’s SKAN support?</summary><p>No. While the Firebase SDK is one option advertisers can use to implement the SKAN methods necessary for Google&#39;s iOS 14 campaign measurement, apps can continue to use another third party (including the Branch SDK) for that functionality.</p></details><details><summary>Why is ACe called out specifically as being significantly impacted?</summary><p>The SKAdNetwork framework is meant for acquisition (app install) campaigns. Therefore reengagement campaigns are not supported in this attribution model.</p></details><details><summary>Why will tROAS campaigns no longer be an option on iOS?</summary><p>SKAdNetwork provides significantly less data for optimization, and it&#39;s likely that Google could not find a way to implement tROAS behavior within the limitations of this framework.</p></details><details><summary>Can Branch Links still be used in Google ad campaigns?</summary><p>If an advertiser is running a web-based Google campaign using a Branch tracking link, we believe this should remain unaffected (provided that the advertiser app receives user opt-in via the ATT framework for any in-app measurement).</p></details><details><summary>What’s the difference between Google’s ‘modeled conversions’ and Branch’s Predictive Modeling?</summary><p>Even though Google&#39;s &#39;<a href="https://support.google.com/google-ads/answer/10081327" target="_blank" rel="noreferrer">modeled conversions</a>&#39; and Branch&#39;s Predictive Modeling (PREM) might sound similar, they&#39;re totally different under the surface.</p><p>Branch&#39;s PREM system watches events (ad clicks + app installs) to try to identify specific matches for the purpose of attribution. We need event metadata (i.e., IP address, user agent) to do that, which requires user opt-in under Apple&#39;s ATT policy when used for the purpose of ad attribution.</p><p>Google&#39;s modeling doesn&#39;t need any of that data.</p></details><details><summary>Will Google show the ATT prompt and provide device-level data for users that opt in?</summary><p>Google will <em>not</em> show the AppTrackingTransparency prompt in their own apps, but will show it in certain scenarios for AdMob inventory.</p><p>This means that while their existing MMP API endpoint will continue to return device-level data <em>in addition</em> to SKAdNetwork if the user opts in on both ends, volume will likely be extremely low.</p></details><details><summary>Does Branch support in-app conversion postbacks to ads via GBRAID?</summary><p>Yes, Branch supports Google&#39;s new <code>gbraid</code> URL parameter for privacy-compliant conversion Postbacks.</p><p>Google currently requires apps to be individually approved — please reach out to your Google Account Manager to request allowlisting.</p></details><details><summary>Is there currently any way to access SKAdNetwork data for Google campaigns?</summary><p>While SKAdNetwork data is not currently available to MMPs via API, Google Account Managers have the ability to generate limited SKAdNetwork reports for their clients. We recommend reaching out to your Google contact for more information.</p></details><details><summary>How will DoubleClick and DV360 campaigns be measured after ATT enforcement?</summary><p>Google is still exploring reporting options for DoubleClick and DV360 campaigns after AppTrackingTransparency goes into effect.</p></details>',11)])])}const g=a(s,[["render",r]]);export{h as __pageData,g as default};
